// src/pages/Dashboard.jsx
// Shows task summary stats for the logged-in user

import { useState, useEffect } from 'react';
import API from '../api/axios';
import { useAuth } from '../context/AuthContext';

const Dashboard = () => {
  const [tasks, setTasks] = useState([]);
  const [loading, setLoading] = useState(true);
  const { user } = useAuth();

  useEffect(() => {
    const fetchMyTasks = async () => {
      try {
        const { data } = await API.get('/tasks/my-tasks');
        setTasks(data.tasks);
      } catch (err) {
        console.error('Failed to load tasks');
      } finally {
        setLoading(false);
      }
    };
    fetchMyTasks();
  }, []);

  // Calculate stats
  const total = tasks.length;
  const todo = tasks.filter(t => t.status === 'todo').length;
  const inProgress = tasks.filter(t => t.status === 'in-progress').length;
  const done = tasks.filter(t => t.status === 'done').length;
  const overdue = tasks.filter(t => {
    return t.dueDate && new Date(t.dueDate) < new Date() && t.status !== 'done';
  }).length;

  const stats = [
    { label: 'Total Tasks', value: total, color: '#3b82f6', bg: '#eff6ff' },
    { label: 'To Do', value: todo, color: '#f59e0b', bg: '#fffbeb' },
    { label: 'In Progress', value: inProgress, color: '#8b5cf6', bg: '#f5f3ff' },
    { label: 'Done', value: done, color: '#10b981', bg: '#ecfdf5' },
    { label: 'Overdue ⚠️', value: overdue, color: '#ef4444', bg: '#fef2f2' },
  ];

  if (loading) return <div>Loading dashboard...</div>;

  return (
    <div style={styles.container}>
      <h2>👋 Welcome back, {user?.name}!</h2>
      <p style={styles.sub}>Here's your task summary</p>

      {/* Stats cards */}
      <div style={styles.grid}>
        {stats.map((stat) => (
          <div key={stat.label} style={{ ...styles.card, backgroundColor: stat.bg }}>
            <div style={{ ...styles.value, color: stat.color }}>{stat.value}</div>
            <div style={styles.label}>{stat.label}</div>
          </div>
        ))}
      </div>

      {/* Overdue tasks list */}
      {overdue > 0 && (
        <div style={styles.overdueSection}>
          <h3>⚠️ Overdue Tasks</h3>
          {tasks
            .filter(t => t.dueDate && new Date(t.dueDate) < new Date() && t.status !== 'done')
            .map(task => (
              <div key={task._id} style={styles.overdueCard}>
                <strong>{task.title}</strong>
                <span style={styles.overdueDate}>
                  Due: {new Date(task.dueDate).toLocaleDateString()}
                </span>
              </div>
            ))}
        </div>
      )}

      {/* Recent tasks */}
      <h3>📋 My Recent Tasks</h3>
      {tasks.slice(0, 5).map(task => (
        <div key={task._id} style={styles.taskRow}>
          <span>{task.title}</span>
          <span style={{
            ...styles.statusBadge,
            background: task.status === 'done' ? '#dcfce7' : task.status === 'in-progress' ? '#dbeafe' : '#fef3c7'
          }}>
            {task.status}
          </span>
        </div>
      ))}

      {tasks.length === 0 && (
        <p style={{ color: '#94a3b8' }}>No tasks assigned to you yet.</p>
      )}
    </div>
  );
};

const styles = {
  container: { maxWidth: '900px', margin: '0 auto' },
  sub: { color: '#64748b', marginTop: '-8px' },
  grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(160px, 1fr))', gap: '16px', margin: '24px 0' },
  card: { padding: '20px', borderRadius: '12px', textAlign: 'center' },
  value: { fontSize: '36px', fontWeight: 'bold' },
  label: { color: '#64748b', fontSize: '13px', marginTop: '4px' },
  overdueSection: { background: '#fef2f2', padding: '20px', borderRadius: '12px', marginBottom: '24px' },
  overdueCard: { display: 'flex', justifyContent: 'space-between', padding: '10px 0', borderBottom: '1px solid #fecaca' },
  overdueDate: { color: '#ef4444', fontSize: '13px' },
  taskRow: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '12px', background: 'white', borderRadius: '8px', marginBottom: '8px', boxShadow: '0 1px 4px rgba(0,0,0,0.06)' },
  statusBadge: { padding: '4px 12px', borderRadius: '20px', fontSize: '12px' },
};

export default Dashboard;
